        3 & -1\\
        -1 & 3
    \end{pmatrix}
    \begin{pmatrix}
        x_1\\
        x_2
    \end{pmatrix}
\end{equation*}

Having found the matrix $A$ and since $n=2$, it is sufficient to apply the formula (eq:integrali-gaussiani-multidimensionale-risultato-Z):

\begin{equation*}
    Z(A)=\sqrt{\frac{(2\pi)^2}{9-1}}=\frac{2\pi}{\sqrt{8}}=\frac{\cancel{2}\pi}{\cancel{2}\sqrt{2}}=\frac{\pi}{\sqrt{2}}
