*Verify that, in the limit* $\lambda\to\infty$:

\begin{align*}
    &1. \ \int_{-2}^0e^te^{\lambda\left(3t^2+2t^3\right)}dt\simeq e^{\lambda-1}\sqrt{\frac{\pi}{3\lambda}}\\
    &2. \ \int_0^1e^te^{\lambda\left(3t^2+2t^3\right)}dt\simeq\frac{e^{5\lambda+1}}{12\lambda}\\
    &3. \ \int_0^1\sqrt{1+t}e^{\lambda\left(2t-t^2\right)}dt\simeq e^\lambda\sqrt{\frac{\pi}{2\lambda}}\\
    &4. \ \int_{-1}^2\left(1+t^2\right)e^{\lambda\left(t^3-t\right)}dt\simeq\frac{5e^{6\lambda}}{11\lambda}
\end{align*}

To solve these integrals according to the Laplace method, one must understand in which of the three cases each of these falls and trivially apply the relative formula.

\begin{enumerate}
    \item $f(t)=3t^2+2t^3 \ \Longrightarrow \ f'(t)=6t+6t^2=6t(1+t) \ \Longrightarrow \ f''(t)=6+12t$

    The stationary points are $t=0$ and $t=-1$. From the second derivative it is observed that $f''(-1)=-6$ and $f''(0)=6$, so we consider $t=-1$ as it is the maximum.
    $f(-1) = 3-2=1$. $g(-1)=e^{-1}$.
    The function goes down for $t\to-\infty$ so we are sure that $t_0=-1$ is the maximum in the interval; being an internal point we fall into the first case and apply (eq:metodo-di-laplace-termine-dominante).

    \begin{equation*}
        \int_{-2}^0e^te^{\lambda\left(3t^2+2t^3\right)}dt\simeq g(-1)e^{\lambda f(-1)}\sqrt{\frac{2\pi}{\lambda\abs{f''(-1)}}}=e^{-1}e^\lambda\sqrt{\frac{2\pi}{6\lambda}}=e^{\lambda-1}\sqrt{\frac{\pi}{3\lambda}}
    \end{equation*}

    \item The function $f(t)$ is the same as in the previous case. In the interval $[0,1]$, $f'(t) &gt; 0$, so the function is increasing. The maximum value is reached at $t_0=1$, which is at the end of the interval and is not a stationary point. $f(1)=5$, $f'(1)=12$, $g(1)=e$. We fall into the third case (formula (eq:metodo-di-laplace-caso-3)).

    \begin{equation*}
        \int_0^1e^te^{\lambda\left(3t^2+2t^3\right)}dt\simeq g(1)\frac{e^{\lambda f(1)}}{\lambda f'(1)} = e\frac{e^{5\lambda}}{12\lambda}=\frac{e^{5\lambda+1}}{12\lambda}
    \end{equation*}

    \item $f(t)=2t-t^2 \ \Longrightarrow \ f'(t)=2-2t \ \Longrightarrow \ f''(t)=-2$

    The only stationary point is $t_0=1$ which is also the absolute maximum point of the function. It follows that, being an end of the interval, we fall into the second case and we must use the formula (eq:metodo-di-laplace-caso-2).
    $f(1)=1$, $g(1)=\sqrt{2}$.
    \begin{equation*}
        \int_0^1\sqrt{1+t}e^{\lambda\left(2t-t^2\right)}dt\simeq g(1)e^{\lambda f(1)}\sqrt{\frac{\pi}{2\lambda\abs{f''(1)}}}=\sqrt{2}e^{\lambda}\sqrt{\frac{\pi}{4\lambda}}=e^\lambda\sqrt{\frac{\pi}{2\lambda}}
    \end{equation*}

    \item $f(t)=t^3-t \ \Longrightarrow \ f'(t)=3t^2-1 \ \Longrightarrow \ f''(t)=6t$

    The two stationary points are $t=\pm\frac{1}{\sqrt{3}}$ which both fall in the interval $[-1,2]$. The values assumed by the second derivative are $f''\left(-\frac{1}{\sqrt{3}}\right)=-\frac{6}{\sqrt{3}}&lt;0$ (max) and $f''\left(\frac{1}{\sqrt{3}}\right)=\frac{6}{\sqrt{3}}&gt;0$ (min).
    $f(-1/\sqrt{3}) = -1/(3\sqrt{3}) + 1/\sqrt{3} = 2/(3\sqrt{3})$.
    We must also check the endpoints. $f(-1)=0$, $f(2)=8-2=6$. The maximum is at $t_0=2$. It is not a stationary point for the function and is at the end of the interval, so we fall into the third case.
    $f(2)=6$, $f'(2)=3(4)-1=11$, $g(2)=1+2^2=5$.
    \begin{equation*}
        \int_{-1}^2\left(1+t^2\right)e^{\lambda\left(t^3-t\right)}dt\simeq g(2)\frac{e^{\lambda f(2)}}{\lambda f'(2)} = 5\frac{e^{6\lambda}}{11\lambda}
    \end{equation*}
\end{enumerate}


